/// Divergence audit: `bessel_k(nu, x)` vs `scipy.special.kv(nu, x)` over the
/// full (nu, x) grid, relative tolerance 1e-6. Reports the worst (nu, x) and
/// the full mismatch list on failure.
#[test]
fn bessel_k_matches_scipy_grid() {
    let mut worst_rel = 0.0_f64;
    let mut worst: (f64, f64, f64, f64) = (0.0, 0.0, 0.0, 0.0);
    let mut mismatches: Vec<String> = Vec::new();
    for &(nu, x, expected) in ORACLE {
        let got = bessel_k(nu, x);
        let rel = ((got - expected) / expected).abs();
        if rel > worst_rel {
            worst_rel = rel;
            worst = (nu, x, got, expected);
        }
        if rel >= 1e-6 || rel.is_nan() {
            mismatches.push(format!(
                "bessel_k({nu}, {x}) = {got:e}, scipy = {expected:e}, rel = {rel:e}"
            ));
        }
    }
    assert!(
        mismatches.is_empty(),
        "{} of {} grid points exceed rel 1e-6 vs scipy.special.kv; \
         worst rel {:e} at (nu={}, x={}) got={:e} scipy={:e}\n{}",
        mismatches.len(),
        ORACLE.len(),
        worst_rel,
        worst.0,
        worst.1,
        worst.2,
        worst.3,
        mismatches.join("\n")
    );
}
